const SOURCE_W = 1280;
const SOURCE_H = 720;
const DEFAULT_TEXT_COLOR = "111827";
const DEFAULT_MUTED_COLOR = "4B5563";
const MAX_SLIDE_ELEMENTS = 60;

type HtmlDiv = {
  tag: string;
  inner: string;
};

type Paint = {
  color: string;
  opacity?: number;
};

function htmlDeckToDeck(source: typeof data): Deck {
  return {
    title: source.title ?? "Neo General",
    description:
      "A converted HTML deck rendered as editable slide elements in the current editor architecture.",
    theme: {
      background: "FFFFFF",
      surface: "FFFFFF",
      primary: "9234EB",
      secondary: "101828",
      accent: "9333EA",
      text: "111827",
      muted: "4B5563",
    },
    slides: source.slides.map((slide, index) => htmlSlideToSlide(slide.html, index)),
  };
}

function htmlSlideToSlide(html: string, index: number): Slide {
  const background = parseSlideBackground(html);
  const elements = extractAbsoluteDivs(html)
    .map((div, elementIndex) => htmlDivToElement(div, elementIndex))
    .filter((element): element is SlideElement => element != null)
    .slice(0, MAX_SLIDE_ELEMENTS);

  return {
    title: inferSlideTitle(elements) ?? `Slide ${index + 1}`,
    background,
    elements: elements.length > 0 ? elements : [fallbackElement()],
  };
}

function extractAbsoluteDivs(html: string): HtmlDiv[] {
  const divs: HtmlDiv[] = [];
  let cursor = 0;
  while (cursor < html.length) {
    const start = html.indexOf("<div", cursor);
    if (start < 0) break;
    const tagEnd = html.indexOf(">", start);
    if (tagEnd < 0) break;
    const tag = html.slice(start, tagEnd + 1);
    if (!/\babsolute\b/.test(tag)) {
      cursor = tagEnd + 1;
      continue;
    }

    let depth = 1;
    let search = tagEnd + 1;
    while (depth > 0) {
      const nextOpen = html.indexOf("<div", search);
      const nextClose = html.indexOf("</div>", search);
      if (nextClose < 0) break;
      if (nextOpen >= 0 && nextOpen < nextClose) {
        depth += 1;
        search = nextOpen + 4;
      } else {
        depth -= 1;
        search = nextClose + 6;
      }
    }

    divs.push({ tag, inner: html.slice(tagEnd + 1, search - 6) });
    cursor = search;
  }
  return divs;
}

function htmlDivToElement(div: HtmlDiv, index: number): SlideElement | null {
  const box = parseBox(div.tag);
  if (!box) return null;

  const image = div.inner.match(/<img\s+[^>]*src=["']([^"']+)["']/);
  if (image?.[1]) {
    return {
      kind: "image",
      ...box,
      data: decodeHtml(image[1]),
      fit: "cover",
      name: `Neo image ${index + 1}`,
    };
  }

  const text = extractText(div.inner);
  if (text) {
    const textStyle = parseTextStyle(div.tag, div.inner);
    return {
      kind: "text",
      ...box,
      text,
      fontFace: "Poppins",
      fontSize: textStyle.fontSize,
      bold: textStyle.bold,
      italic: textStyle.italic,
      color: textStyle.color,
      align: textStyle.align,
      lineHeight: textStyle.lineHeight,
    };
  }

  const paint = parsePaint(div.tag);
  const line = parseLine(div.tag);
  if (!paint && !line) return null;

  return {
    kind: "rect",
    ...box,
    fill: paint?.color ?? "FFFFFF",
    opacity: paint?.opacity,
    line,
  };
}

function parseBox(tag: string) {
  const x = parsePxClass(tag, "left");
  const y = parsePxClass(tag, "top");
  const w = parsePxClass(tag, "w");
  const h = parsePxClass(tag, "h");
  if (x == null || y == null || w == null || h == null) return null;
  return {
    x: pxToSlideX(x),
    y: pxToSlideY(y),
    w: Math.max(0.01, pxToSlideX(w)),
    h: Math.max(0.01, pxToSlideY(h)),
  };
}

function parsePxClass(tag: string, name: string) {
  const match = tag.match(new RegExp(`${name}-\\[(-?\\d+(?:\\.\\d+)?)px\\]`));
  return match ? Number(match[1]) : null;
}

function parseSlideBackground(html: string) {
  const match = html.match(/slide-content[^>]*\bbg-\[([^\]]+)\]/);
  return parsePaintValue(match?.[1])?.color ?? "FFFFFF";
}

function parsePaint(tag: string): Paint | null {
  const match = tag.match(/\bbg-\[([^\]]+)\]/);
  return parsePaintValue(match?.[1]);
}

function parsePaintValue(raw?: string): Paint | null {
  if (!raw) return null;
  if (raw === "white") return { color: "FFFFFF" };
  if (raw === "black") return { color: "000000" };
  if (/^#[0-9A-Fa-f]{6}$/.test(raw)) return { color: stripHash(raw) };

  const rgba = raw.match(/rgba\((\d+),\s*(\d+),\s*(\d+),\s*([0-9.]+)\)/);
  if (!rgba) return null;
  return {
    color: rgbToHex(Number(rgba[1]), Number(rgba[2]), Number(rgba[3])),
    opacity: clamp(Number(rgba[4]), 0, 1),
  };
}

function parseLine(tag: string) {
  const color = tag.match(/\bborder-\[(#[0-9A-Fa-f]{6})\]/)?.[1];
  if (!color) return undefined;
  return {
    color: stripHash(color),
    width: parsePxClass(tag, "border") ?? 1,
  };
}

function parseTextStyle(tag: string, inner: string) {
  const spanClass = inner.match(/<span[^>]*class=["']([^"']*)["']/)?.[1] ?? "";
  const styleText = `${tag} ${inner} ${spanClass}`;
  const fontSizePx = Number(styleText.match(/text-\[([0-9.]+)px\]/)?.[1] ?? 16);
  const color = styleText.match(/text-\[(#[0-9A-Fa-f]{6})\]/)?.[1];
  const lineHeight = Number(inner.match(/line-height:\s*([0-9.]+)/)?.[1] ?? 1.2);
  return {
    fontSize: clamp(pxToPt(fontSizePx), 6, 360),
    color: color ? stripHash(color) : DEFAULT_MUTED_COLOR,
    bold: /\bfont-bold\b/.test(styleText) || undefined,
    italic: /\bitalic\b/.test(styleText) || undefined,
    align: /\btext-center\b/.test(styleText)
      ? "center"
      : /\btext-right\b/.test(styleText)
        ? "right"
        : undefined,
    lineHeight: clamp(lineHeight, 0.8, 2.2),
  } as const;
}

function extractText(inner: string) {
  if (!/<span\b/.test(inner)) return "";
  const withBreaks = inner
    .replace(/<\/div>\s*<div/gi, "\n<div")
    .replace(/<br\s*\/?>/gi, "\n");
  const text = decodeHtml(withBreaks.replace(/<[^>]+>/g, ""));
  return text.replace(/[\u2002-\u200A\u202F\u205F\u3000]/g, " ").replace(/\s+/g, " ").trim();
}

function inferSlideTitle(elements: SlideElement[]) {
  const title = elements.find(
    (element) =>
      element.kind === "text" &&
      element.bold &&
      element.fontSize >= 20 &&
      element.text.length <= 80,
  );
  return title?.kind === "text" ? title.text : undefined;
}

function fallbackElement(): SlideElement {
  return {
    kind: "text",
    x: 0.6,
    y: 0.6,
    w: 8.8,
    h: 0.4,
    text: "Empty slide",
    fontFace: "Poppins",
    fontSize: 18,
    color: DEFAULT_TEXT_COLOR,
  };
}

function pxToSlideX(value: number) {
  return round((value / SOURCE_W) * SLIDE_W);
}

function pxToSlideY(value: number) {
  return round((value / SOURCE_H) * SLIDE_H);
}

function pxToPt(value: number) {
  return round((value / SOURCE_W) * SLIDE_W * 72);
}

function stripHash(color: string) {
  return color.replace("#", "").toUpperCase();
}

function rgbToHex(r: number, g: number, b: number) {
  return [r, g, b]
    .map((value) => clamp(value, 0, 255).toString(16).padStart(2, "0"))
    .join("")
    .toUpperCase();
}

function decodeHtml(value: string) {
  return value
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&nbsp;/g, " ");
}

function clamp(value: number, min: number, max: number) {
  return Math.min(max, Math.max(min, value));
}

function round(value: number) {
  return Math.round(value * 1000) / 1000;
}

export const neoGeneralDeck = htmlDeckToDeck(data);
